cat > src/main.js << 'EOF'
import * as THREE from 'three';

class SolarSystem {
  constructor() {
    this.container = document.createElement('div');
    this.container.className = 'solar-system';
    document.body.appendChild(this.container);

    this.scene = new THREE.Scene();
    this.camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 100000);
    this.renderer = new THREE.WebGLRenderer({ antialias: true });
    this.renderer.setSize(window.innerWidth, window.innerHeight);
    this.renderer.setPixelRatio(window.devicePixelRatio);

    this.container.appendChild(this.renderer.domElement);

    this.time = 0;
    this.timeStep = 1;
    this.playing = false;
    this.animationId = null;

    this.bodies = [];
    this.lines = [];

    this.initLights();
    this.initControls();
    this.initUI();

    this.loadData();
  }

  initLights() {
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    this.scene.add(ambientLight);

    const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
    directionalLight.position.set(100, 100, 100);
    this.scene.add(directionalLight);
  }

  initControls() {
    this.controls = {
      time: 0,
      timeSpeed: 1,
      playing: false,
      filter: {
        hazardous: false,
        distance: [0, Infinity],
        type: 'all'
      }
    };

    const gui = new dat.GUI();
    gui.add(this.controls, 'time', 0, 3000, 1).name('Time (days)');
    gui.add(this.controls, 'timeSpeed', 0.01, 10).name('Speed');
    gui.add(this.controls, 'playing').name('Playing');

    const filterFolder = gui.addFolder('Filters');
    filterFolder.add(this.controls.filter, 'hazardous').name('Hazardous Only');
  }

  initUI() {
    const style = document.createElement('style');
    style.textContent = `
      body { margin: 0; padding: 0; overflow: hidden; background: #000; }
      .solar-system { width: 100vw; height: 100vh; }
      .ui { position: absolute; top: 10px; left: 10px; color: white; font-family: monospace; }
      .controls { margin-top: 20px; }
    `;
    document.head.appendChild(style);

    const ui = document.createElement('div');
    ui.className = 'ui';
    ui.innerHTML = `
      <h1>Solar System Visualization</h1>
      <div class="controls">
        <button id="play-pause">Play/Pause</button>
        <button id="reset-time">Reset</button>
        <input type="range" id="time-slider" min="0" max="3000" value="0">
      </div>
    `;
    this.container.appendChild(ui);

    document.getElementById('play-pause').addEventListener('click', () => {
      this.controls.playing = !this.controls.playing;
    });

    document.getElementById('reset-time').addEventListener('click', () => {
      this.controls.time = 0;
      this.controls.playing = false;
    });

    document.getElementById('time-slider').addEventListener('input', (e) => {
      this.controls.time = parseFloat(e.target.value);
      this.controls.playing = false;
    });
  }

  async loadData() {
    this.controls.time = 0;

    try {
      const planetsResp = await fetch('./data/planets.json');
      const planets = await planetsResp.json();
      this.createBodies(planets, 'planet');

      const asteroidsResp = await fetch('./data/asteroids.json');
      const asteroids = await asteroidsResp.json();
      this.createBodies(asteroids, 'asteroid');

      const cometsResp = await fetch('./data/comets.json');
      const comets = await cometsResp.json();
      this.createBodies(comets, 'comet');

      console.log('Loaded', planets.length, 'planets,', asteroids.length, 'asteroids,', comets.length, 'comets');
      this.animate();
    } catch (error) {
      console.error('Failed to load data:', error);
    }
  }

  createBodies(data, type) {
    const colorMap = {
      'planet': 0x808080,
      'asteroid': 0x888888,
      'comet': 0xffffff
    };

    for (const obj of data) {
      if (!this.shouldShow(obj)) continue;

      const body = this.createBody(obj, type);
      this.bodies.push(body);
    }
  }

  shouldShow(body) {
    if (body.neo && body.pha && this.controls.filter.hazardous) {
      return true;
    }

    const dist = body.class === 'IEO' ? body.moid || Infinity : (body.q || 0);

    return dist >= this.controls.filter.distance[0] &&
           dist <= this.controls.filter.distance[1] &&
           (this.controls.filter.type === 'all' || 
            (this.controls.filter.type === 'planet' && body.name) ||
            (this.controls.filter.type === 'asteroid' && body.class && !body.name) ||
            (this.controls.filter.type === 'comet' && body.class === 'C'));
  }

  createBody(obj, type) {
    const geometry = new THREE.SphereGeometry(0.01, 16, 16);

    let radius = 0.01;
    if (obj.name && obj.radius_km) {
      radius = obj.radius_km / 696000; // Convert km to Sun radii
    } else if (obj.diameter) {
      radius = (obj.diameter / 2) / 696000;
    }

    const material = new THREE.MeshPhongMaterial({
      color: type === 'planet' ? 0x808080 : type === 'asteroid' ? 0x888888 : 0xffff00,
      emissive: 0x111111,
      emissiveIntensity: type === 'comet' ? 0.2 : 0
    });

    const body = new THREE.Mesh(geometry, material);
    body.userData = {
      type: type,
      name: obj.name || obj.pdes || obj.full_name || `object-${Math.random()}`,
      data: obj
    };

    body.position.set(0, 0, 0);
    this.scene.add(body);

    if (type === 'asteroid') {
      const orbitLine = this.createOrbitLine(obj);
      this.lines.push(orbitLine);
      this.scene.add(orbitLine);
    }

    return body;
  }

  createOrbitLine(body) {
    const points = [];
    const segments = 64;

    const a = body.a;
    const e = body.e;
    const i = THREE.MathUtils.degToRad(body.i);
    const om = THREE.MathUtils.degToRad(body.om);
    const w = THREE.MathUtils.degToRad(body.w);
    const ma0 = THREE.MathUtils.degToRad(body.ma || 0);
    const epoch = body.epoch;

    const dt = 365.25 * 36525; // 1000 years
    const steps = segments;

    for (let j = 0; j <= steps; j++) {
      const currentTime = epoch + (j / steps) * dt;

      const ma = ma0 + body.n * (currentTime - epoch);
      const ea = this.solveKepler(ma, e);
      const nu = 2 * Math.atan(Math.sqrt((1 + e) / (1 - e)) * Math.tan(ea / 2));

      const r = a * (1 - e * Math.cos(ea));

      let x = r * Math.cos(nu);
      let y = r * Math.sin(nu);

      const Rx = new THREE.Matrix4()
        .makeRotationZ(om)
        .multiply(new THREE.Matrix4().makeRotationX(i))
        .multiply(new THREE.Matrix4().makeRotationZ(w));

      const v = new THREE.Vector3(x, y, 0);
      Rx.applyToVector3(v);

      points.push(new THREE.Vector3(v.x, v.y, v.z));
    }

    const geometry = new THREE.BufferGeometry().setFromPoints(points);
    const material = new THREE.LineBasicMaterial({
      color: 0x888888,
      transparent: true,
      opacity: 0.3
    });

    return new THREE.Line(geometry, material);
  }

  solveKepler(meanAnomaly, eccentricity) {
    let eccentricityAnomaly = meanAnomaly;

    for (let i = 0; i < 10; i++) {
      const delta = meanAnomaly - eccentricityAnomaly + eccentricity * Math.sin(eccentricityAnomaly);
      eccentricityAnomaly += delta / (1 - eccentricity * Math.cos(eccentricityAnomaly));
    }

    return eccentricityAnomaly;
  }

  animate() {
    this.animationId = requestAnimationFrame(() => this.animate());

    if (this.controls.playing) {
      this.controls.time += this.controls.timeSpeed * this.timeStep;
    }

    for (const body of this.bodies) {
      this.updateBodyPosition(body);
    }

    this.updateUI();
    this.renderer.render(this.scene, this.camera);
  }

  updateBodyPosition(body) {
    const timeOffset = (this.controls.time - body.userData.data.epoch) / 32400000; // Convert days to years

    const data = body.userData.data;

    let a = data.a;
    let e = data.e;
    let i = THREE.MathUtils.degToRad(data.i);
    let om = THREE.MathUtils.degToRad(data.om);
    let w = THREE.MathUtils.degToRad(data.w);
    let ma0 = THREE.MathUtils.degToRad(data.ma || 0);
    let epoch = data.epoch;
    let n = data.n;

    if (!n) {
      n = Math.sqrt(0.00029458 / Math.pow(a, 3)); // Mean motion for closed orbits
      if (isNaN(n) || n <= 0) {
        n = 0.00057373;
      }
    }

    if (data.e >= 1) {
      ma0 = 0;
      n = 0;
    }

    const meanAnomaly = ma0 + n * timeOffset;
    const ea = this.solveKepler(meanAnomaly, e);
    const nu = 2 * Math.atan(Math.sqrt((1 + e) / (1 - e)) * Math.tan(ea / 2));

    const r = a * (1 - e * Math.cos(ea));

    let x = r * Math.cos(nu);
    let y = r * Math.sin(nu);
    let z = 0;

    const Rx = new THREE.Matrix4()
      .makeRotationZ(om)
      .multiply(new THREE.Matrix4().makeRotationX(i))
      .multiply(new THREE.Matrix4().makeRotationZ(w));

    const v = new THREE.Vector3(x, y, z);
    Rx.applyToVector3(v);

    body.position.set(v.x, v.y, v.z);

    if (body.userData.type === 'comet' && data.e >= 1) {
      const scale = data.e > 1.2 ? 1.5 : 1;
      body.scale.set(scale, scale, scale);
    }
  }

  updateUI() {
    document.getElementById('time-slider').value = this.controls.time;
  }

  dispose() {
    cancelAnimationFrame(this.animationId);

    this.bodies.forEach(body => {
      this.scene.remove(body);
      body.geometry.dispose();
      body.material.dispose();
    });

    this.lines.forEach(line => {
      this.scene.remove(line);
      line.geometry.dispose();
      line.material.dispose();
    });

    this.renderer.dispose();
  }
}

window.addEventListener('resize', () => {
  window.camera = window.scene = window.renderer = null;
  window.onload();
});

window.onload = () => {
  window.app = new SolarSystem();

  window.scene = window.app.scene;
  window.camera = window.app.camera;
  window.renderer = window.app.renderer;
};

