    let eccentricityAnomaly = meanAnomaly;

    for (let i = 0; i < 10; i++) {
      const delta = meanAnomaly - eccentricityAnomaly + eccentricity * Math.sin(eccentricityAnomaly);
      eccentricityAnomaly += delta / (1 - eccentricity * Math.cos(eccentricityAnomaly));
