    let om = THREE.MathUtils.degToRad(data.om);
    let w = THREE.MathUtils.degToRad(data.w);
    let ma0 = THREE.MathUtils.degToRad(data.ma || 0);
    let epoch = data.epoch;
    let n = data.n;

