      .makeRotationZ(om)
      .multiply(new THREE.Matrix4().makeRotationX(i))
      .multiply(new THREE.Matrix4().makeRotationZ(w));

    const v = new THREE.Vector3(x, y, z);
    Rx.applyToVector3(v);

    body.position.set(v.x, v.y, v.z);

    if (body.userData.type === 'comet' && data.e >= 1) {
      const scale = data.e > 1.2 ? 1.5 : 1;
      body.scale.set(scale, scale, scale);
    }
  }

  updateUI() {
    if (document.getElementById('time-slider')) {
      document.getElementById('time-slider').value = this.controls.time;
    }
  }

